class ServiceContainer:
    def __init__(self):
        self._services = {}

    def register(self, interface, implementation):
        self._services[interface] = implementation

    def resolve(self, interface):
        impl = self._services.get(interface)
        if impl is None:
            raise ValueError(f"No implementation for {interface}")
        return impl()

class UserService:
    def __init__(self, repo: UserRepository):
        self._repo = repo

container = ServiceContainer()
container.register(UserRepository, MySQLUserRepository)
user_service = UserService(container.resolve(UserRepository))

class MessageBus:
    def __init__(self):
        self._handlers: dict[str, list[Handler]] = {}

    def register_handler(self, event_type: str, handler: Handler):
        self._handlers.setdefault(event_type, []).append(handler)

    def send(self, event: Event):
        for handler in self._handlers.get(event.type, []):
            handler.handle(event)

class OrderPlacedEvent(Event):
    def __init__(self, order_id: str):
        self.type = "order.placed"
        self.data = {"order_id": order_id}

class EmailHandler(Handler):
    def handle(self, event: Event):
        print(f"Sending email for {event.data['order_id']}")

bus = MessageBus()
bus.register_handler("order.placed", EmailHandler())
bus.send(OrderPlacedEvent("12345"))

